var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"10년 전","JPN":"10年前","ENG":"10 years ago","TWN":"10年前","SCN":"10年前","DEU":"10 years ago","FRA":"10 years ago"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>캄파멘토</color>\\n해발 고도 약 6,500m 지점 <color=#ffd34c>태풍이 노래하는 천공섬</color>","JPN":"管理局直轄都市<color=#ffd34c>カンパメント</color>\\n標高約6,500m地点、<color=#ffd34c>台風が唄う天空島</color>","ENG":"[[","TWN":"管理局直轄市 <color=#ffd34c>坎帕門托</color>\\n海拔約 6,500m處<color=#ffd34c>颱風在熱舞的天空島</color>","SCN":"管理局直属城市<color=#ffd34c>坎帕门托</color>\\n海拔高度约6,500米处<color=#ffd34c>台风歌唱的天空岛</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"작전조! 에어리어 세타 도착했습니다!","JPN":"作戦チーム！　エリアシータに着きました！","ENG":"Operations Team! We've reached Area Theta!","TWN":"作戰小組！已抵達希塔區域！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"정화 작전을 개시한다! 전방에 일제사격 개시!","JPN":"浄化作戦を開始する！　前方に向けて一斉射撃開始！","ENG":"Commence the purification operation! Open fire on the front line!","TWN":"開始淨化作戰！朝前方發射！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이 빌어먹을 침식체 녀석들……!!","JPN":"このくそ侵食体ども……！！","ENG":"Blasted C.O.s...!","TWN":"這些該死的侵蝕體……！！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"한 마리도 남겨놓지 말고, 전부 쏴 버려……!!","JPN":"一匹残らず、全部撃ち殺しちまえ……！！","ENG":"Don't leave a single one standing! Wipe them all out!","TWN":"一個都不要留下，全都殺光……！！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸, 작전조로부터 연락이 왔습니다.","JPN":"カン、作戦チームからの連絡です。","ENG":"Khan, the operations team just reported in.","TWN":"坎，作戰組來聯絡了。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이번 마을도 틀린 것 같습니다. 침식체들에 의해서 쑥대밭이 되었어요.","JPN":"今回の村も手遅れのようです。侵食体によって廃墟と化してしまったと。","ENG":"This village is gone too. The C.O.s reduced it to rubble.","TWN":"這個村子好像也沒能倖免，被侵蝕體搞得一團糟。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇군. 그거 애석한 일이야.","JPN":"そうか。残念じゃったのう。","ENG":"I see. What a shame.","TWN":"是嗎，真是遺憾。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"애초에 천공섬 마을 주민들은 침식현상에 대한 방비가 제대로 이루어지지 않아요.","JPN":"そもそも天空島の村の人々は、侵食現象に対する防備がまともにできていません。","ENG":"The floating island villages never had proper defenses against the Counterside Effect.","TWN":"本來天空島村莊的居民對侵蝕現象的防備就沒有做好。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"지금이라도 관리국 정책을 바꿔서, 원주민 이주 정책을 펼쳐야 합니다.","JPN":"今からでも管理局の政策を変更し、先住民移住政策を推進すべきです。","ENG":"The Administration needs to change policy and begin relocation programs for the natives.","TWN":"現在應該改變管理局政策，推行原住民遷移政策。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그들에게는 그들의 삶의 터전이 있는 법이야.","JPN":"彼らには彼らの居場所があるのじゃ。","ENG":"They have their own homelands, Wade.","TWN":"他們有他們的生活的家園。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이곳 아마존 유역 일대는 관리 실패가 발생하기 전에도, 원래 그들의 땅이었네.","JPN":"ここ、アマゾン流域一帯は管理失敗が発生する前から彼らの土地じゃった。","ENG":"Even before the Administration Failure, this Amazon basin was theirs.","TWN":"亞馬遜流域一帶在管理失敗發生之前就是他們的土地。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"관리를 명목으로 섣부르게 간섭하려다간, 훗날 그들의 문명 자체가 사라지고 말 거야.","JPN":"管理という建前で無闇に干渉しては、いずれ彼らの文明は滅んでしまう。","ENG":"If we intrude rashly under the pretense of management, their civilization itself could vanish one day.","TWN":"以管理為名貿然干涉的話，日後他們的文明本身將會消失。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"사람이 살아남아야 문명이 이어지는 겁니다!","JPN":"人あっての文明です！","ENG":"Civilization survives only if people survive!","TWN":"只有人類生存下去，文明才能延續！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그들은 관리가 필요해요! 그들의 무지가 침식현상을 숭배하는 결과로 이어진다고요!","JPN":"彼らには管理が必要です！　彼らの無知は、侵食現象への崇拝につながるのです！","ENG":"They need the Administration! Their ignorance is what leads them to worship the Counterside Effect!","TWN":"但是他們需要管理！他們的無知會導致崇拜侵蝕的現象！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그들의 무지? 말 조심하게, 웨이드.","JPN":"彼らの無知じゃと？　口を慎め、ウェイド。","ENG":"Ignorance? Watch your words, Wade.","TWN":"他們無知？小心你的言辭，韋德。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"우리가 그들보다 우월하다고 생각하는 건, 그저 현대인의 오만한 편견일 뿐이야.","JPN":"我々が彼らより優れているという意識は、現代人の傲慢な偏見にすぎん。","ENG":"Thinking ourselves superior is nothing but modern arrogance.","TWN":"我們認為自己比他們優越，這只不過是現代人的傲慢偏見而已。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그들에게는 그들의 질서가 있네, 웨이드.","JPN":"彼らには彼らの秩序があるのじゃ、ウェイド。","ENG":"They have their own order, Wade.","TWN":"他們有他們的秩序，韋德。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"어쩌면 그들은 침식현상에 대해, 관리국보다도 훨씬 더 많은 걸 알고 있을지도 모르지.","JPN":"もしかすると、彼らは侵食現象について、管理局よりも多くの情報を持っているかもしれんぞ。","ENG":"They may even understand the Counterside Effect better than the Administration.","TWN":"說不定他們對侵蝕現象的瞭解，甚至比管理局還要多。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그렇지만……!","JPN":"ですが……！","ENG":"But still...!","TWN":"可是……！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님! 원주민 마을에서 생존자를 발견하였습니다……!","JPN":"シニア！　先住民の村で生存者を見つけました……！","ENG":"Senior! We found a survivor in the village...!","TWN":"Senior！在原住民村莊發現倖存者……！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아이의 상태는 어떤가……?","JPN":"子どもの様子はどうじゃ……？","ENG":"What's the child's condition...?","TWN":"……孩子的狀態怎麼樣？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOCTOR_ADMIN_WHITE_NULL","text":{"KOREA":"다행히 큰 외상은 없습니다. 침식 증후군 증세도 음성이고요.","JPN":"幸い、外見上の大きな怪我はありません。侵食症候群の検査結果も陰性でした。","ENG":"Fortunately, no serious injuries. No signs of Corruption Syndrome either.","TWN":"幸好沒有嚴重的外傷，侵蝕綜合症的症狀也呈陰性。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOCTOR_ADMIN_WHITE_NULL","text":{"KOREA":"다만, 정신적인 쇼크 때문인지 아이가 말을 하지 않습니다.","JPN":"ただ、精神的なショックのせいか、まったく喋りません。","ENG":"But the child hasn't spoken, likely from shock.","TWN":"只是，由於精神上的衝擊，孩子不肯說話。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"……그렇군.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_ADMIN_WHITE_NULL","text":{"KOREA":"하지만 역시 이상하네요.","JPN":"しかし……やはり不思議です。","ENG":"But it's strange.","TWN":"不過還是有些奇怪呢。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_ADMIN_WHITE_NULL","text":{"KOREA":"침식파 억제 장치조차 없는 침식지대 마을에서 자라난 아이인데.","JPN":"侵食波抑制装置すらない侵食地帯の村で育った子なのに……","ENG":"This child grew up in a village in a Corrupted Area with no Corruption Inhibitors...","TWN":"在沒有侵蝕波抑制裝置的侵蝕地帶村莊長大的孩子，"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"L22_1","JPN":"L22_1","ENG":"L22_1","TWN":"L22_1","SCN":"L22_1","DEU":"L22_1","FRA":"L22_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"subtitle","speaker":null,"text":{"KOREA":"L23_1","JPN":"L23_1","ENG":"L23_1","TWN":"L23_1","SCN":"L23_1","DEU":"L23_1","FRA":"L23_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};